    async def fetch_markets(self, params={}) -> List[Market]:
        """
        fetches all active limitless markets paginated and returns one CCXT market per child market, each containing a list of outcome objects(YES/NO)

        https://docs.limitless.exchange/api-reference/markets/get-active-markets

        :param dict [params]: extra parameters specific to the exchange API endpoint
        :param str [params.query]: a single search query string to filter markets by
        :param str[] [params.queries]: multiple search query strings(alternative to query)
        :param int [params.limit]: max number of markets to collect(defaults to options.fetchMarketsLimit, 1000); caps the pages fetched
        :returns dict[]: an array of objects representing market data
        """
        queries = self.parse_search_queries(params)
        rest = self.omit(params, ['query', 'queries', 'limit'])
        # scope the listing: without a search query loadMarkets would otherwise page through
        # every active limitless market. Cap the total number of markets collected.
        maxMarkets = self.safe_integer(params, 'limit', self.safe_integer(self.options, 'fetchMarketsLimit', 1000))
        allRaw = []
        queriesLength = len(queries)
        if queries and queriesLength > 0:
            limit = self.safe_integer(rest, 'limit', 50)
            searchRest = self.omit(rest, ['limit'])
            seen = {}
            for i in range(0, len(queries)):
                q = queries[i]
                response = await self.limitlessPublicGetMarketsSearch(self.extend({'query': q, 'limit': limit}, searchRest))
                found = self.safe_list(response, 'markets', [])
                for j in range(0, len(found)):
                    raw = found[j]
                    slug = self.safe_string(raw, 'slug')
                    if slug and not (slug in seen):
                        seen[slug] = True
                        allRaw.append(raw)
        else:
            page = 1
            pageSize = self.safe_integer(self.options, 'marketsPageSize', 25)
            request = {
                'page': page,
                'limit': pageSize,
            }
            firstPageResponse = await self.limitlessPublicGetMarketsActive(self.extend(request, rest))
            totalMarketsCount = self.safe_integer(firstPageResponse, 'totalMarketsCount')
            firstData = self.safe_list(firstPageResponse, 'data', [])
            allRaw = self.array_concat(allRaw, firstData)
            promises = []
            cappedPages = int(math.ceil(maxMarkets / pageSize))
            allPages = int(math.ceil(totalMarketsCount / pageSize))
            totalPages = min(allPages, cappedPages)
            for i in range(2, totalPages):
                page = i
                request['page'] = page
                promises.append(self.limitlessPublicGetMarketsActive(self.extend(request, rest)))
            responses = await asyncio.gather(*promises)
            length = len(responses)
            for j in range(0, length):
                response = self.safe_dict(responses, j)
                data = self.safe_list(response, 'data', [])
                allRaw = self.array_concat(allRaw, data)
            lastPageResponse = self.safe_dict(responses, length - 1)
            lastPageData = self.safe_list(lastPageResponse, 'data', [])
            lastPageLength = len(lastPageData)
            allRawLength = len(allRaw)
            if lastPageLength >= pageSize and allRawLength < maxMarkets:
                while(True):
                    page = self.sum(page, 1)
                    request['page'] = page
                    response = await self.limitlessPublicGetMarketsActive(self.extend(request, rest))
                    rawPageMarkets = self.safe_list(response, 'data', response)
                    page_markets = rawPageMarkets if (rawPageMarkets is not None) else []
                    pageMarketsLength = len(page_markets)
                    if not page_markets or pageMarketsLength == 0:
                        break
                    for i in range(0, len(page_markets)):
                        raw = page_markets[i]
                        allRaw.append(raw)
                    allRawCount = len(allRaw)
                    if pageMarketsLength < pageSize or allRawCount >= maxMarkets:
                        break
        markets = []
        eventGroups = {}
        for i in range(0, len(allRaw)):
            raw = allRaw[i]
            groupId = self.safe_string(raw, 'groupId', self.safe_string(raw, 'slug'))
            eventKey = self.shorten_slug(groupId) if groupId else None
            m = self.parse_market(raw)
            markets.append(m)
            if eventKey:
                if not (eventKey in eventGroups):
                    eventGroups[eventKey] = {'groupId': groupId, 'title': self.safe_string(raw, 'title', groupId), 'raw': raw, 'markets': []}
                eventGroup = eventGroups[eventKey]
                eventGroup['markets'].append(m)
        eventsDict = {}
        eventKeys = list(eventGroups.keys())
        for i in range(0, len(eventKeys)):
            eventKey = eventKeys[i]
            g = eventGroups[eventKey]
            eventsDict[eventKey] = self.parse_event(g)
        self.events = eventsDict
        marketsLength = len(markets)
        if marketsLength > maxMarkets:
            return self.array_slice(markets, 0, maxMarkets)
        return markets

